example.code:
# module_a.py
from module_b import helper_function

def my_function():
    return helper_function()

# test_a.py — WRONG
def test_bad_mock_target(mocker):
    mocker.patch("module_b.helper_function", return_value="mocked")
    result = my_function()
    # Still calls real helper_function — mock is on the wrong binding

def test_user_repository_save(mocker): # autospec ensures mock matches real UserRepository.save signature mock_repo = mocker.create_autospec(UserRepository) mock_repo.save.return_value = User(id=1, email="test@example.com")
service = UserService(repository=mock_repo) result = service.create_user(email="test@example.com")
assert result.id == 1 mock_repo.save.assert_called_once()

def test_logging_called_on_error(mocker): spy_logger = mocker.spy(app.services.logger, "error")
with pytest.raises(ValidationError): validate_user({"email": "invalid"})
spy_logger.assert_called_once() call_args = spy_logger.call_args[0][0] assert "Validation failed" in call_args

@pytest.mark.asyncio async def test_async_external_service(mocker): mock_fetch = mocker.patch( "app.services.external_api.fetch_data", new_callable=mocker.AsyncMock, ) mock_fetch.return_value = {"data": "mocked"}
result = await process_external_data()
assert result["data"] == "mocked" mock_fetch.assert_awaited_once()
@pytest.mark.asyncio async def test_async_exception_handling(mocker): mocker.patch( "app.services.external_api.fetch_data", new_callable=mocker.AsyncMock, side_effect=ConnectionError("Service unavailable"), )
with pytest.raises(ServiceError): await process_external_data()

def test_user_service_minimal_mocking(mocker, db): mocker.patch("app.services.email_client.send", return_value=True)
result = UserService.register(email="test@example.com")
assert result.id is not None assert User.objects.filter(email="test@example.com").exists()
